	  	{
	  		case 1:
				//청구부서코드팝업			
	  			pCode = ed_bilgLodeptCd.getValue().replace(/\s*$/, '');		// 청구부서코드
	  			pName = ed_bilgLodeptNm.getValue();		// 청구부서명

                udc_bilgLodeptCd.setSelectId('retrieveOpDeptCdInfo');
	  			//rtnList = cfCommonPopUp('retrieveOpDeptCdInfo'	// XML상의 SELECT ID	
